'use client';

import { useState } from 'react';
import { useCartStore } from '@/store/cartStore';
import { Button } from '@/components/ui/Button';
import { MapPin, CreditCard, ChevronRight } from 'lucide-react';
import { useRouter } from 'next/navigation';

export default function CheckoutPage() {
    const { items, getTotalPrice, clearCart } = useCartStore();
    const [address, setAddress] = useState('123 Main St, New Delhi');
    const [payment, setPayment] = useState('Credit Card ending in 4242');
    const router = useRouter();

    if (items.length === 0) {
        return (
            <div className="max-w-3xl mx-auto p-4 md:p-8 text-center pt-24">
                <h1 className="text-2xl font-bold mb-4">Your cart is empty</h1>
                <Button onClick={() => router.push('/')}>Browse Restaurants</Button>
            </div>
        );
    }

    const handlePlaceOrder = () => {
        // In real app, call API
        clearCart();
        router.push('/tracking/ord-123');
    };

    return (
        <div className="max-w-4xl mx-auto p-4 md:p-8 pb-24 h-full">
            <h1 className="text-2xl font-bold mb-8">Checkout</h1>

            <div className="flex flex-col md:flex-row gap-8">
                <div className="flex-1 space-y-6">
                    {/* Address */}
                    <section className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                        <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                            <MapPin className="text-brand" /> Delivery Address
                        </h2>
                        <div className="p-4 border border-brand bg-brand/5 rounded-xl flex items-center justify-between cursor-pointer">
                            <div>
                                <span className="font-semibold block mb-1">Home</span>
                                <span className="text-gray-600 text-sm">{address}</span>
                            </div>
                            <Button variant="ghost" className="text-brand hover:bg-brand/10">Change</Button>
                        </div>
                        <Button variant="outline" fullWidth className="mt-4 border-dashed text-brand border-brand/50 bg-brand/5 hover:bg-brand/10">
                            + Add New Address
                        </Button>
                    </section>

                    {/* Payment */}
                    <section className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                        <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                            <CreditCard className="text-brand" /> Payment Method
                        </h2>
                        <div className="p-4 border rounded-xl flex items-center justify-between cursor-pointer hover:border-brand hover:bg-brand/5 transition-colors">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-6 bg-gray-200 rounded" />
                                <span className="font-medium">{payment}</span>
                            </div>
                            <ChevronRight className="w-5 h-5 text-gray-400" />
                        </div>
                    </section>
                </div>

                {/* Summary */}
                <div className="w-full md:w-96 shrink-0 space-y-4">
                    <section className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 sticky top-24">
                        <h2 className="text-lg font-semibold mb-4">Order Summary</h2>
                        <div className="space-y-4 mb-4">
                            {items.map(item => (
                                <div key={item.id} className="flex justify-between text-sm">
                                    <span className="text-gray-700">{item.quantity} x {item.name}</span>
                                    <span className="font-medium">Γé╣{item.price * item.quantity}</span>
                                </div>
                            ))}
                        </div>

                        <div className="border-t pt-4 space-y-2 text-sm text-gray-500">
                            <div className="flex justify-between">
                                <span>Item Total</span>
                                <span>Γé╣{getTotalPrice()}</span>
                            </div>
                            <div className="flex justify-between">
                                <span>Delivery Fee</span>
                                <span>Γé╣40</span>
                            </div>
                            <div className="flex justify-between">
                                <span>Taxes & Charges</span>
                                <span>Γé╣35</span>
                            </div>
                        </div>

                        <div className="border-t border-dashed mt-4 pt-4 flex justify-between font-bold text-lg text-gray-900">
                            <span>To Pay</span>
                            <span>Γé╣{getTotalPrice() + 75}</span>
                        </div>

                        <Button fullWidth size="lg" className="mt-6 text-lg shadow-md" onClick={handlePlaceOrder}>
                            Place Order
                        </Button>
                    </section>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { Star, Clock } from 'lucide-react';
import { useCartStore } from '@/store/cartStore';

const MOCK_RESTAURANT = {
    id: 'rest-1',
    name: 'Burger King',
    rating: 4.2,
    deliveryTime: '25',
    costForTwo: 'Γé╣350 for two',
    tags: ['American', 'Fast Food', 'Burgers'],
    address: 'Connaught Place, New Delhi',
};

const MENU = [
    {
        category: 'Recommended',
        items: [
            { id: 'item-1', name: 'Whopper', price: 179, desc: 'Our signature burger with flame-grilled patty.', isVeg: false },
            { id: 'item-2', name: 'Veg Whopper', price: 149, desc: 'Our signature veg burger with crispy patty.', isVeg: true },
        ]
    },
    {
        category: 'Sides & Beverages',
        items: [
            { id: 'item-3', name: 'French Fries', price: 99, desc: 'Classic salted fries.', isVeg: true },
            { id: 'item-4', name: 'Pepsi', price: 60, desc: 'Chilled beverage.', isVeg: true },
        ]
    }
];

export default function RestaurantDetailPage({ params }: { params: { id: string } }) {
    const [activeTab, setActiveTab] = useState('Menu');
    const addItem = useCartStore(state => state.addItem);

    const handleAdd = (item: any) => {
        addItem({
            id: item.id,
            name: item.name,
            price: item.price,
            isVeg: item.isVeg,
            restaurantId: MOCK_RESTAURANT.id,
            restaurantName: MOCK_RESTAURANT.name
        });
    };

    return (
        <div className="pb-24">
            {/* Banner */}
            <div className="h-48 md:h-72 bg-gray-200 w-full relative">
                <div className="absolute inset-0 bg-black/20" />
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 -mt-8 relative z-10 w-full">
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
                    <div className="flex flex-col md:flex-row md:justify-between md:items-start gap-4">
                        <div>
                            <h1 className="text-3xl font-bold mb-2">{MOCK_RESTAURANT.name}</h1>
                            <p className="text-gray-500 mb-2">{MOCK_RESTAURANT.tags.join(', ')}</p>
                            <p className="text-sm text-gray-400">{MOCK_RESTAURANT.address}</p>
                        </div>

                        <div className="flex items-center gap-6">
                            <div className="flex flex-col items-center justify-center p-2 rounded-xl border border-gray-100 bg-gray-50">
                                <div className="flex items-center gap-1 font-bold text-green-700">
                                    {MOCK_RESTAURANT.rating} <Star className="w-4 h-4 fill-green-700" />
                                </div>
                                <span className="text-xs text-gray-500 mt-1">1K+ Ratings</span>
                            </div>
                        </div>
                    </div>

                    <div className="flex items-center gap-6 mt-6 pt-6 border-t border-gray-100">
                        <div className="flex items-center gap-2">
                            <Clock className="w-5 h-5 text-gray-400" />
                            <span className="font-medium text-gray-700">{MOCK_RESTAURANT.deliveryTime} mins</span>
                        </div>
                        <div className="w-1 h-1 rounded-full bg-gray-300" />
                        <div className="flex items-center gap-2">
                            <span className="font-medium text-gray-700">{MOCK_RESTAURANT.costForTwo}</span>
                        </div>
                    </div>
                </div>

                {/* Tabs */}
                <div className="flex items-center gap-8 border-b border-gray-200 mt-8 sticky top-16 bg-background z-20 pt-4 overflow-x-auto hide-scrollbar">
                    {['Menu', 'Reviews', 'Info'].map((tab) => (
                        <button
                            key={tab}
                            onClick={() => setActiveTab(tab)}
                            className={`pb-4 text-lg font-medium transition-colors border-b-2 whitespace-nowrap ${activeTab === tab ? 'border-brand text-brand' : 'border-transparent text-gray-500 hover:text-gray-900'
                                }`}
                        >
                            {tab}
                        </button>
                    ))}
                </div>

                {/* Menu Content */}
                {activeTab === 'Menu' && (
                    <div className="flex flex-col md:flex-row gap-8 mt-8">
                        {/* Sidebar Desktop */}
                        <div className="hidden md:block w-64 shrink-0 border-r border-gray-100 pr-4">
                            <ul className="sticky top-40 space-y-2">
                                {MENU.map((category) => (
                                    <li key={category.category}>
                                        <button className="text-gray-600 hover:text-brand font-medium text-left w-full px-4 py-2 rounded-lg hover:bg-gray-50">
                                            {category.category}
                                        </button>
                                    </li>
                                ))}
                            </ul>
                        </div>

                        {/* Menu Items */}
                        <div className="flex-1 space-y-12">
                            {MENU.map((category) => (
                                <div key={category.category} id={category.category.toLowerCase().replace(/\s+/g, '-')}>
                                    <h2 className="text-2xl font-bold mb-6">{category.category}</h2>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        {category.items.map((item) => (
                                            <div key={item.id} className="flex justify-between gap-4 p-4 rounded-2xl border border-gray-100 hover:shadow-md transition-shadow bg-white">
                                                <div className="flex-1">
                                                    <div className={`w-4 h-4 border flex items-center justify-center rounded-sm mb-2 ${item.isVeg ? 'border-green-500' : 'border-red-500'}`}>
                                                        <div className={`w-2 h-2 rounded-full ${item.isVeg ? 'bg-green-500' : 'bg-red-500'}`} />
                                                    </div>
                                                    <h3 className="font-semibold text-lg text-gray-900">{item.name}</h3>
                                                    <div className="font-medium mt-1">Γé╣{item.price}</div>
                                                    <p className="text-sm text-gray-500 mt-2 line-clamp-2">{item.desc}</p>
                                                </div>
                                                <div className="flex flex-col items-center justify-center shrink-0 w-28 md:w-32 relative">
                                                    <div className="w-full h-24 bg-gray-100 rounded-xl mb-4 overflow-hidden flex items-center justify-center">
                                                        <span className="text-[10px] text-gray-400">Photo</span>
                                                    </div>
                                                    <button
                                                        onClick={() => handleAdd(item)}
                                                        className="absolute -bottom-3 bg-white text-green-600 border border-gray-200 shadow-sm font-bold uppercase px-8 py-2 rounded-lg hover:bg-gray-50 transition-colors"
                                                    >
                                                        Add
                                                    </button>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { Filter, ChevronDown } from 'lucide-react';
import RestaurantCard from '@/components/restaurant/RestaurantCard';

const MOCK_RESTAURANTS = Array.from({ length: 8 }).map((_, i) => ({
    id: `rest-${i}`,
    name: `Restaurant ${i + 1}`,
    rating: Number((Math.random() * 2 + 3).toFixed(1)),
    deliveryTime: `${Math.floor(Math.random() * 30) + 15}`,
    costForTwo: 'Γé╣400 for two',
    tags: ['North Indian', 'Chinese', 'Fast Food'].slice(0, Math.floor(Math.random() * 3) + 1),
    imageUrl: '',
    offer: i % 3 === 0 ? '50% OFF up to Γé╣100' : undefined,
}));

export default function SearchPage() {
    const [activeFilter, setActiveFilter] = useState('Relevance');

    return (
        <div className="px-4 py-8 md:py-12 max-w-7xl mx-auto space-y-8 pb-24 md:pb-12">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <h1 className="text-3xl font-bold">Delivery Restaurants in New Delhi</h1>

                {/* Filters */}
                <div className="flex items-center gap-3 overflow-x-auto hide-scrollbar pb-2 md:pb-0">
                    <button className="flex items-center gap-2 px-4 py-2 bg-white border rounded-xl text-sm font-medium hover:bg-gray-50 shadow-sm shrink-0">
                        <Filter className="w-4 h-4" /> Filters
                    </button>
                    <button className="flex items-center gap-2 px-4 py-2 bg-white border rounded-xl text-sm font-medium hover:bg-gray-50 shadow-sm shrink-0">
                        Sort by: {activeFilter} <ChevronDown className="w-4 h-4 ml-1" />
                    </button>
                    <button className="px-4 py-2 bg-white border rounded-xl text-sm font-medium hover:bg-gray-50 shadow-sm shrink-0">
                        Pure Veg
                    </button>
                    <button className="px-4 py-2 bg-white border rounded-xl text-sm font-medium hover:bg-gray-50 shadow-sm shrink-0">
                        Rating: 4.0+
                    </button>
                </div>
            </div>

            {/* Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
                {MOCK_RESTAURANTS.map((restaurant) => (
                    <RestaurantCard key={restaurant.id} {...restaurant} />
                ))}
            </div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Minus, Plus, ShoppingBag } from 'lucide-react';
import { useCartStore } from '@/store/cartStore';
import { Button } from '@/components/ui/Button';

interface CartDrawerProps {
    isOpen: boolean;
    onClose: () => void;
}

export default function CartDrawer({ isOpen, onClose }: CartDrawerProps) {
    const { items, removeItem, updateQuantity, getTotalPrice } = useCartStore();
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
    }, []);

    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'auto';
        }
        return () => {
            document.body.style.overflow = 'auto';
        };
    }, [isOpen]);

    if (!mounted) return null;

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/50 z-50 transition-opacity"
                        onClick={onClose}
                    />
                    <motion.div
                        initial={{ x: '100%' }}
                        animate={{ x: 0 }}
                        exit={{ x: '100%' }}
                        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                        className="fixed inset-y-0 right-0 z-50 w-full md:w-[400px] bg-white shadow-2xl flex flex-col"
                    >
                        {/* Header */}
                        <div className="flex items-center justify-between p-4 border-b">
                            <h2 className="text-xl font-bold">Your Cart</h2>
                            <button
                                onClick={onClose}
                                className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500 hover:text-black"
                            >
                                <X className="w-5 h-5" />
                            </button>
                        </div>

                        {/* Content */}
                        <div className="flex-1 overflow-y-auto p-4 flex flex-col gap-4">
                            {items.length === 0 ? (
                                <div className="flex flex-col items-center justify-center flex-1 text-gray-400 gap-4">
                                    <ShoppingBag className="w-16 h-16 opacity-20" />
                                    <p className="font-medium text-gray-500">Your cart is empty</p>
                                    <p className="text-sm">Add something from the menu</p>
                                </div>
                            ) : (
                                items.map((item) => (
                                    <div key={item.id} className="flex flex-col gap-2 p-3 border rounded-xl shadow-sm bg-white">
                                        <div className="flex justify-between items-start">
                                            <div className="flex items-start gap-2">
                                                <span className={`mt-1 text-xs border p-0.5 rounded-sm flex items-center justify-center w-4 h-4 ${item.isVeg ? 'border-green-500 text-green-500' : 'border-red-500 text-red-500'}`}>
                                                    ΓùÅ
                                                </span>
                                                <div>
                                                    <h4 className="font-medium text-sm text-gray-800">{item.name}</h4>
                                                    <span className="text-sm font-semibold">Γé╣{item.price}</span>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex justify-between items-center mt-2">
                                            <span className="text-xs text-gray-500">Qty: {item.quantity}</span>
                                            <div className="flex items-center bg-brand/10 border border-brand/20 rounded-lg overflow-hidden">
                                                <button
                                                    onClick={() => updateQuantity(item.id, item.quantity - 1)}
                                                    className="w-8 h-8 flex items-center justify-center text-brand hover:bg-brand/20 transition-colors"
                                                >
                                                    <Minus className="w-4 h-4" />
                                                </button>
                                                <span className="w-8 text-center text-sm font-medium text-brand">{item.quantity}</span>
                                                <button
                                                    onClick={() => updateQuantity(item.id, item.quantity + 1)}
                                                    className="w-8 h-8 flex items-center justify-center text-brand hover:bg-brand/20 transition-colors"
                                                >
                                                    <Plus className="w-4 h-4" />
                                                </button>
                                            </div>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>

                        {/* Footer */}
                        {items.length > 0 && (
                            <div className="p-4 border-t bg-gray-50 shrink-0">
                                <div className="flex items-center justify-between mb-4">
                                    <span className="font-semibold text-gray-700">Total</span>
                                    <span className="font-bold text-xl">Γé╣{getTotalPrice()}</span>
                                </div>
                                <Button fullWidth onClick={() => { }} className="text-lg h-12">
                                    Proceed to Checkout
                                </Button>
                            </div>
                        )}
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
}

import Link from 'next/link';
import { Star, Clock } from 'lucide-react';

interface RestaurantCardProps {
    id: string;
    name: string;
    rating: number;
    deliveryTime: string;
    costForTwo: string;
    tags: string[];
    imageUrl: string;
    offer?: string;
}

export default function RestaurantCard({
    id,
    name,
    rating,
    deliveryTime,
    costForTwo,
    tags,
    imageUrl,
    offer
}: RestaurantCardProps) {
    return (
        <Link href={`/restaurant/${id}`} className="group block">
            <div className="relative overflow-hidden rounded-2xl bg-white border border-gray-100 transition-all hover:shadow-xl hover:-translate-y-1 hover:border-gray-200">
                <div className="relative aspect-[4/3] w-full overflow-hidden bg-gray-100 flex items-center justify-center">
                    <span className="text-gray-400">Image: {name}</span>
                    {offer && (
                        <div className="absolute bottom-3 left-0 bg-blue-600 text-white text-xs font-bold px-3 py-1 rounded-r-lg shadow-sm">
                            {offer}
                        </div>
                    )}
                </div>

                <div className="p-4">
                    <div className="flex justify-between items-start mb-1">
                        <h3 className="font-bold text-lg text-gray-900 truncate pr-2">{name}</h3>
                        <div className="flex items-center gap-1 bg-green-700 text-white px-2 py-0.5 rounded-lg text-xs font-bold shrink-0">
                            {rating} <Star className="w-3 h-3 fill-white" />
                        </div>
                    </div>

                    <div className="flex justify-between items-center text-gray-500 text-sm mb-3">
                        <span className="truncate">{tags.join(', ')}</span>
                        <span className="shrink-0 ml-2">{costForTwo}</span>
                    </div>

                    <div className="flex items-center gap-1 text-gray-500 text-xs pt-3 border-t border-gray-100">
                        <Clock className="w-4 h-4 text-brand" />
                        <span className="font-medium">{deliveryTime} min delivery</span>
                    </div>
                </div>
            </div>
        </Link>
    );
}

import api from './api';

export const AuthService = {
    login: async (credentials: any) => {
        const response = await api.post('/auth/login', credentials);
        return response.data;
    },
    register: async (data: any) => {
        const response = await api.post('/auth/register', data);
        return response.data;
    },
    getProfile: async () => {
        const response = await api.get('/auth/profile');
        return response.data;
    }
};

import api from './api';

export const OrderService = {
    createOrder: async (data: any) => {
        const response = await api.post('/orders', data);
        return response.data;
    },
    getOrderById: async (id: string) => {
        const response = await api.get(`/orders/${id}`);
        return response.data;
    },
    getUserOrders: async () => {
        const response = await api.get('/orders/user');
        return response.data;
    }
};

import api from './api';

export const RestaurantService = {
    getRestaurants: async (params?: any) => {
        const response = await api.get('/restaurants', { params });
        return response.data;
    },
    getRestaurantById: async (id: string) => {
        const response = await api.get(`/restaurants/${id}`);
        return response.data;
    },
    getRestaurantMenu: async (id: string) => {
        const response = await api.get(`/restaurants/${id}/menu`);
        return response.data;
    }
};

import { create } from 'zustand';

export interface Order {
    id: string;
    restaurantId: string;
    items: any[];
    total: number;
    status: 'pending' | 'preparing' | 'on_the_way' | 'delivered' | 'cancelled';
    createdAt: string;
}

interface OrderState {
    currentOrder: Order | null;
    orders: Order[];
    setOrders: (orders: Order[]) => void;
    setCurrentOrder: (order: Order | null) => void;
    updateOrderStatus: (orderId: string, status: Order['status']) => void;
}

export const useOrderStore = create<OrderState>()((set) => ({
    currentOrder: null,
    orders: [],
    setOrders: (orders) => set({ orders }),
    setCurrentOrder: (currentOrder) => set({ currentOrder }),
    updateOrderStatus: (orderId, status) => set((state) => ({
        orders: state.orders.map((o) => o.id === orderId ? { ...o, status } : o),
        currentOrder: state.currentOrder?.id === orderId ? { ...state.currentOrder, status } : state.currentOrder
    }))
}));
